import axios from 'axios';

const API_BASE_URL = 'http://localhost:3000/api';

// Add request interceptor to include auth token
examAPI.interceptors.request.use(
    (config) => {
        const token = localStorage.getItem('token');
        if (token) {
            config.headers.Authorization = `Bearer ${token}`;
        }
        return config;
    },
    (error) => {
        return Promise.reject(error);
    }
);

// Get all exams with advanced filtering and pagination
export const getAllExams = async (options = {}) => {
    try {
        const {
            page = 1,
            limit = 20,
            subjectId,
            difficulty,
            status,
            search,
            sortBy = 'createdAt',
            sortOrder = 'desc'
        } = options;

        const params = new URLSearchParams();
        params.append('page', page);
        params.append('limit', limit);
        params.append('sortBy', sortBy);
        params.append('sortOrder', sortOrder);
        
        if (subjectId) params.append('subjectId', subjectId);
        if (difficulty) params.append('difficulty', difficulty);
        if (status) params.append('status', status);
        if (search) params.append('search', search);

        const response = await examAPI.get(`/?${params.toString()}`);
        return response.data;
    } catch (error) {
        console.error('Error fetching exams:', error);
        throw error;
    }
};

// Get exam by ID
export const getExam = async (id) => {
    try {
        const response = await examAPI.get(`/${id}`);
        return response.data;
    } catch (error) {
        console.error('Error fetching exam:', error);
        throw error;
    }
};

// Create a new exam
export const createExam = async (examData) => {
    try {
        const response = await examAPI.post('/', examData);
        return response.data;
    } catch (error) {
        console.error('Error creating exam:', error);
        throw error;
    }
};

// Update exam
export const updateExam = async (id, examData) => {
    try {
        const response = await examAPI.put(`/${id}`, examData);
        return response.data;
    } catch (error) {
        console.error('Error updating exam:', error);
        throw error;
    }
};

// Delete exam (soft delete)
export const deleteExam = async (id) => {
    try {
        const response = await examAPI.delete(`/${id}`);
        return response.data;
    } catch (error) {
        console.error('Error deleting exam:', error);
        throw error;
    }
};

// Submit exam
export const submitExam = async (submissionData) => {
    try {
        const response = await examAPI.post('/submit', submissionData);
        return response.data;
    } catch (error) {
        console.error('Error submitting exam:', error);
        throw error;
    }
};

// Get exams by difficulty
export const getExamsByDifficulty = async (difficulty) => {
    try {
        const response = await examAPI.get(`/difficulty/${difficulty}`);
        return response.data;
    } catch (error) {
        console.error('Error fetching exams by difficulty:', error);
        throw error;
    }
};

// Get exams by subject
export const getExamsBySubject = async (subjectId) => {
    try {
        const response = await examAPI.get(`/subject/${subjectId}`);
        return response.data;
    } catch (error) {
        console.error('Error fetching exams by subject:', error);
        throw error;
    }
};

// Get active exams only
export const getActiveExams = async () => {
    try {
        const response = await examAPI.get('/?status=active');
        return response.data;
    } catch (error) {
        console.error('Error fetching active exams:', error);
        throw error;
    }
};

// Get exams with basic filters (simplified version for quick access)
export const getFilteredExams = async (filters = {}) => {
    try {
        const { difficulty, subjectId, isActive = true } = filters;
        const params = new URLSearchParams();
        
        if (difficulty) params.append('difficulty', difficulty);
        if (subjectId) params.append('subjectId', subjectId);
        if (isActive) params.append('status', 'active');
        
        const response = await examAPI.get(`/?${params.toString()}`);
        return response.data;
    } catch (error) {
        console.error('Error fetching filtered exams:', error);
        throw error;
    }
};

export default {
    getAllExams,
    getExam,
    createExam,
    updateExam,
    deleteExam,
    submitExam,
    getExamsByDifficulty,
    getExamsBySubject,
    getActiveExams,
    getFilteredExams
};
